{
  "summary": "This paper proposes a method to incorporate structural locality features into kNN-based non-parametric language models to improve retrieval quality and language modeling performance. By adjusting retrieval distances with learned linear functions based on hierarchical locality indicators, the approach yields consistent improvements in perplexity and token prediction accuracy on Wikipedia text and Java source code datasets with minimal additional parameters and training.",
  "strengths": [
    {
      "point": "Effective integration of structural locality into kNN-LMs",
      "evidence": "The method leverages domain-specific hierarchical features (e.g., article sections, project directories) to adjust retrieval distances, improving retrieval relevance and downstream language modeling performance."
    },
    {
      "point": "Demonstrated improvements across diverse domains",
      "evidence": "Experiments on both Wikipedia text and Java source code show consistent gains in perplexity and token prediction accuracy, with especially strong improvements in the Java domain."
    },
    {
      "point": "Parameter-efficient and easy to optimize",
      "evidence": "Only a small number of additional parameters (linear weights and biases per locality feature) are learned on a validation set without retraining the base LM."
    },
    {
      "point": "Insightful analysis of locality effects",
      "evidence": "The paper provides detailed analysis showing that locality features help discriminate among top retrieved neighbors and that traditional embedding similarity alone is insufficient."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited comparison to prior work on structural or hierarchical retrieval signals",
      "evidence": "The Related Work section does not sufficiently situate the approach relative to existing retrieval-augmented LMs that use hierarchical or metadata-based retrieval features."
    },
    {
      "point": "No ablation study on individual locality features",
      "evidence": "The paper does not analyze the contribution of each locality feature separately, leaving unclear which features are most beneficial or if some are redundant."
    },
    {
      "point": "Unjustified choice of linear parameterization for distance adjustment",
      "evidence": "The linear form of \(g_n\) is not compared against alternative nonlinear or embedding-based parameterizations, which may limit expressiveness."
    },
    {
      "point": "Missing baseline using simple feature concatenation",
      "evidence": "No experiments test whether locality features improve performance simply by concatenation to embeddings or as additional LM inputs, rather than modifying retrieval distances."
    },
    {
      "point": "Evaluation lacks retrieval-specific metrics and statistical significance testing",
      "evidence": "Metrics such as precision@k or recall@k for retrieval quality are absent, and reported improvements lack confidence intervals or significance tests."
    },
    {
      "point": "Limited domain diversity and generalizability analysis",
      "evidence": "Experiments are restricted to two domains with clear hierarchical structure; no evaluation on noisy, out-of-domain, or other language/modality datasets."
    },
    {
      "point": "Insufficient reproducibility details",
      "evidence": "Key information on validation set size, optimization procedure, and datastore construction (size, indexing, retrieval speed) is missing."
    },
    {
      "point": "Ambiguity and clarity issues in locality feature definitions and effects",
      "evidence": "The handling of overlapping or ambiguous categories is unclear, and the intuition behind how locality weights affect retrieval probabilities is not well explained."
    },
    {
      "point": "No discussion of scalability or applicability limitations",
      "evidence": "The approach assumes availability of domain-specific hierarchical metadata and does not address scalability to large or dynamic datastores."
    }
  ],
  "questions": [
    {
      "question": "How do individual locality features contribute to performance gains?",
      "motivation": "Understanding which features are most effective can guide feature selection and simplify the model."
    },
    {
      "question": "Would nonlinear or more expressive parameterizations of the distance adjustment function improve results?",
      "motivation": "Exploring alternative parameterizations could enhance the model's ability to capture complex locality effects."
    },
    {
      "question": "How does the method perform on datasets with noisy, incomplete, or absent hierarchical metadata?",
      "motivation": "Evaluating robustness and generalizability is crucial for practical deployment in diverse real-world scenarios."
    },
    {
      "question": "Can locality features improve retrieval quality beyond perplexity and accuracy, as measured by retrieval-specific metrics?",
      "motivation": "Directly measuring retrieval precision or recall would better validate the impact of locality on retrieval."
    },
    {
      "question": "What are the computational and scalability implications of incorporating locality features in large or dynamic datastores?",
      "motivation": "Understanding efficiency and maintenance costs is important for real-world applicability."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
